insert into public.rules (id, source_id, rule_code, title, category, jurisdiction, match_strategy, status, scope) values ('c647d0f1-aeb8-55eb-be23-48584fb98e3c', '6c3ee0f8-1e12-5d31-84da-fb6b04521c80', 'tw-cos-203-646', '牛海綿狀腦病(Bovine Spongiform Encephalopathy)發生國家之牛、羊組織製成之原料 (羊毛脂(Lanolin)、英國產以外之乳製品、英國產以外經鹼性處理之明膠(Gelatin)，以及經破壞致病原處理之脂肪酸(Fatty acid)、胺基酸(Amino acid)及甘油(Glycerin)等牛脂(Tallow)衍生物原料不在此限) (1)牛海綿狀腦病發生之國家，以行政院農業委員會公告動物傳染病非疫區及疫區之國家(地區)為準。 (2)牛、羊組織，包括：腦(Brain)、脊椎(Spinal cord)、眼(Eye)、迴腸(Ileum) 、淋巴結(Lymph nodes)、近端結腸(Proximal Colon)、脾臟(Spleen)、扁桃腺(Tonsil)、硬腦膜(Dura mater)、松果腺(Pineal gland)、胎盤(Placenta)、腦脊椎液(Cerebrospinal fluid)、腦下垂體(Pituitary gland)、腎上腺(Adrenal gland)、遠端結腸(Distal colon)、鼻黏膜(Nasal mucosa)、末梢神經(Peripheral nerves)、骨髓(Bone marrow)、肝臟(Liver)、肺臟(Lung)、胰臟(Pancreas)、胸腺(Thymus gland)。', 'prohibited', 'TW', 'ingredient', 'active', '{"product_scope":"","source_info_id":203}'::jsonb) on conflict (rule_code) do update set title = excluded.title, category = excluded.category, scope = excluded.scope;
