insert into public.rule_versions (id, rule_id, source_id, version_label, source_record_id, source_hash, effective_from, is_current, rule_text, ingredient_names, cas_numbers, color_index_numbers, product_scope, limit_text, restriction_text, caution_text, conditions, raw_payload, source_snapshot) values ('84154d66-8b13-514c-a5b0-150469cefdad', 'b9fca024-9985-5c05-adba-b13c20a12619', '6c3ee0f8-1e12-5d31-84da-fb6b04521c80', '03e8b6d9710a2408', '34', '03e8b6d9710a2408b592e6d3a52aa20f3bf3c4c886657f0bda1ce7a0437bc3fc', '2026-06-25', true, 'Formaldehyde（Formalin） | (1)化粧品中使用DMDM Hydantoin、Imidazolidinyl urea、Quaterium 15、Benzylhemiformal、5-Bromo-5-nitro-1,3-dioxane、Bronopol、Methenamine、Sodium hydroxymethylglycinate、Diazolidinyl urea 成分作為防腐劑時，其總釋出之Free formaldehyde 量，不得超過1000ppm。 (2)未添加DMDM Hydantonin、Imidazolidinyl urea、Quaterium-15、DiaZolidinyl urea、Hexamethylenetetramine、 Benzylhemiformal、5-Bromo-5-nitro-1,3-dioxane、Bronopol 及Sodium hydroxymethylglycinate 等防腐劑成分，如於製造過程中，因所需使用原料或其他因素，且技術上無法避免，致含自然殘留微量時，則其最終製品中所含游離甲醛（Free formaldehyde）之殘留量，不得超過75ppm。', '["Formaldehyde（Formalin）"]'::jsonb, '["50-00-0"]'::jsonb, '[]'::jsonb, '', '', '', '', '{"limit_percent_values":[],"max_limit_percent":null}'::jsonb, '{"編號":"34","成分名稱":"Formaldehyde（Formalin）","CAS_Number":"50-00-0","備註":"(1)化粧品中使用DMDM Hydantoin、Imidazolidinyl urea、Quaterium 15、Benzylhemiformal、5-Bromo-5-nitro-1,3-dioxane、Bronopol、Methenamine、Sodium hydroxymethylglycinate、Diazolidinyl urea 成分作為防腐劑時，其總釋出之Free formaldehyde 量，不得超過1000ppm。\r\n(2)未添加DMDM Hydantonin、Imidazolidinyl urea、Quaterium-15、DiaZolidinyl urea、Hexamethylenetetramine、\r\nBenzylhemiformal、5-Bromo-5-nitro-1,3-dioxane、Bronopol 及Sodium hydroxymethylglycinate 等防腐劑成分，如於製造過程中，因所需使用原料或其他因素，且技術上無法避免，致含自然殘留微量時，則其最終製品中所含游離甲醛（Free formaldehyde）之殘留量，不得超過75ppm。"}'::jsonb, '{"source_url":"https://data.gov.tw/dataset/173684","export_url":"https://data.fda.gov.tw/data/opendata/export/203/json","source_info_id":203}'::jsonb) on conflict (rule_id, version_label) do update set is_current = true, effective_to = null, rule_text = excluded.rule_text, raw_payload = excluded.raw_payload, source_snapshot = excluded.source_snapshot;
