insert into public.rule_versions (id, rule_id, source_id, version_label, source_record_id, source_hash, effective_from, is_current, rule_text, ingredient_names, cas_numbers, color_index_numbers, product_scope, limit_text, restriction_text, caution_text, conditions, raw_payload, source_snapshot) values ('04649a09-be1f-54c0-8d11-272fa9dd7d27', 'b516e7f2-ca29-5830-9d7f-faa11915b047', '846c3ee9-b5b7-52ae-b7e1-400a6e4bdbbb', '5e06d824db6a1729', '17', '5e06d824db6a172995259f9dff12234732a4a74f99ccf8797e21315137e6b20e', '2026-06-25', true, 'Methyl salicylate | 1% | 注意事項（立即沖洗產品得免刊載該注意事項）： 1. 可能使用於二歲以下孩童之產品：二歲以下孩童使用前請諮詢醫師或藥師。 2. Methyl Salicylate 之每日用量不得超過1.8gm，以免引起水楊酸中毒症狀，諸如呼吸困難及其他中樞神經中毒等症狀；對阿斯匹靈或水楊酸有過敏或敏感現象，使用前請諮詢醫師或藥師。', '["Methyl salicylate","Methyl salicylate"]'::jsonb, '["119-36-8"]'::jsonb, '[]'::jsonb, '', '1%', '', '注意事項（立即沖洗產品得免刊載該注意事項）： 1. 可能使用於二歲以下孩童之產品：二歲以下孩童使用前請諮詢醫師或藥師。 2. Methyl Salicylate 之每日用量不得超過1.8gm，以免引起水楊酸中毒症狀，諸如呼吸困難及其他中樞神經中毒等症狀；對阿斯匹靈或水楊酸有過敏或敏感現象，使用前請諮詢醫師或藥師。', '{"limit_percent_values":[1],"max_limit_percent":1}'::jsonb, '{"編號":"17","成分名":"Methyl salicylate\t","INCI名":"Methyl salicylate\t","CAS_NO.":"119-36-8\t","產品類型／使用範圍":null,"限量標準":"1%\t\t","限制規定":null,"應刊載之注意事項":"注意事項（立即沖洗產品得免刊載該注意事項）：\r\n1. 可能使用於二歲以下孩童之產品：二歲以下孩童使用前請諮詢醫師或藥師。\r\n2. Methyl Salicylate 之每日用量不得超過1.8gm，以免引起水楊酸中毒症狀，諸如呼吸困難及其他中樞神經中毒等症狀；對阿斯匹靈或水楊酸有過敏或敏感現象，使用前請諮詢醫師或藥師。"}'::jsonb, '{"source_url":"https://data.gov.tw/dataset/173685","export_url":"https://data.fda.gov.tw/data/opendata/export/199/json","source_info_id":199}'::jsonb) on conflict (rule_id, version_label) do update set is_current = true, effective_to = null, rule_text = excluded.rule_text, raw_payload = excluded.raw_payload, source_snapshot = excluded.source_snapshot;
