insert into public.rules (id, source_id, rule_code, title, category, jurisdiction, match_strategy, status, scope) values ('e823152b-e300-5c98-90b0-c4ed60d6d0bc', '846c3ee9-b5b7-52ae-b7e1-400a6e4bdbbb', 'tw-cos-199-25', 'α-Hydroxy acids(AHA)', 'restricted', 'TW', 'ingredient', 'active', '{"product_scope":"","source_info_id":199}'::jsonb) on conflict (rule_code) do update set title = excluded.title, category = excluded.category, scope = excluded.scope;
insert into public.rule_versions (id, rule_id, source_id, version_label, source_record_id, source_hash, effective_from, is_current, rule_text, ingredient_names, cas_numbers, color_index_numbers, product_scope, limit_text, restriction_text, caution_text, conditions, raw_payload, source_snapshot) values ('af0f66a3-9bd3-5cd4-a975-93ae873c0c24', 'e823152b-e300-5c98-90b0-c4ed60d6d0bc', '846c3ee9-b5b7-52ae-b7e1-400a6e4bdbbb', '3d33d53b972df413', '25', '3d33d53b972df413827255aa0b8b391f3911d3b29825cf038023cd5c5b67dacd', '2026-06-25', true, 'α-Hydroxy acids(AHA) | pH≧3.5; 惟使用後立即沖洗之洗髮或潤髮等產品，其AHA含量為3%以下時，其pH值得為3.2以上至3.5以下。 | 有關pH值檢測方式，依產品實際情形，參照「『中華民國標準』（CNS）化粧品pH值酸鹼性試驗法（總號9036類號S2073）」檢驗之。 | 1. α-Hydroxy acids對皮膚容易引起刺激性，消費者使用時應注意下列事項： (1) 皮膚敏感者，使用前請先作皮膚敏感性測試。 (2) 皮膚有損傷、傷口或紅腫時不得使用。 (3) 嬰兒及孩童不宜使用本產品。 (4) 使用時皮膚如有異常現象，請暫停使用。 (5) 使用後皮膚如有持續紅腫或出現不適應症狀時，請立即就醫診治。 (6) 本產品含α-Hydroxy acids成分，可能增加皮膚對陽光敏感及曬傷可能性。 (7) 使用本產品後必須使用防曬劑、穿著有保護衣物及一個星期內應避免陽光曝曬。 2. 化粧品中含α-Hydroxy acids成分，其含量為10%以下，且產品pH值為3.5以上，作為pH值調整液時，其標籤、仿單或包裝，得免刊載前開注意事項。', '["α-Hydroxy acids(AHA)","-"]'::jsonb, '[]'::jsonb, '[]'::jsonb, '', 'pH≧3.5; 惟使用後立即沖洗之洗髮或潤髮等產品，其AHA含量為3%以下時，其pH值得為3.2以上至3.5以下。', '有關pH值檢測方式，依產品實際情形，參照「『中華民國標準』（CNS）化粧品pH值酸鹼性試驗法（總號9036類號S2073）」檢驗之。', '1. α-Hydroxy acids對皮膚容易引起刺激性，消費者使用時應注意下列事項： (1) 皮膚敏感者，使用前請先作皮膚敏感性測試。 (2) 皮膚有損傷、傷口或紅腫時不得使用。 (3) 嬰兒及孩童不宜使用本產品。 (4) 使用時皮膚如有異常現象，請暫停使用。 (5) 使用後皮膚如有持續紅腫或出現不適應症狀時，請立即就醫診治。 (6) 本產品含α-Hydroxy acids成分，可能增加皮膚對陽光敏感及曬傷可能性。 (7) 使用本產品後必須使用防曬劑、穿著有保護衣物及一個星期內應避免陽光曝曬。 2. 化粧品中含α-Hydroxy acids成分，其含量為10%以下，且產品pH值為3.5以上，作為pH值調整液時，其標籤、仿單或包裝，得免刊載前開注意事項。', '{"limit_percent_values":[3],"max_limit_percent":3}'::jsonb, '{"編號":"25","成分名":"α-Hydroxy acids(AHA)","INCI名":"-","CAS_NO.":"-","產品類型／使用範圍":null,"限量標準":"pH≧3.5;\r\n惟使用後立即沖洗之洗髮或潤髮等產品，其AHA含量為3%以下時，其pH值得為3.2以上至3.5以下。\r\n","限制規定":"有關pH值檢測方式，依產品實際情形，參照「『中華民國標準』（CNS）化粧品pH值酸鹼性試驗法（總號9036類號S2073）」檢驗之。","應刊載之注意事項":"1. α-Hydroxy acids對皮膚容易引起刺激性，消費者使用時應注意下列事項：\r\n(1) 皮膚敏感者，使用前請先作皮膚敏感性測試。\r\n(2) 皮膚有損傷、傷口或紅腫時不得使用。\r\n(3) 嬰兒及孩童不宜使用本產品。\r\n(4) 使用時皮膚如有異常現象，請暫停使用。\r\n(5) 使用後皮膚如有持續紅腫或出現不適應症狀時，請立即就醫診治。\r\n(6) 本產品含α-Hydroxy acids成分，可能增加皮膚對陽光敏感及曬傷可能性。\r\n(7) 使用本產品後必須使用防曬劑、穿著有保護衣物及一個星期內應避免陽光曝曬。\r\n2. 化粧品中含α-Hydroxy acids成分，其含量為10%以下，且產品pH值為3.5以上，作為pH值調整液時，其標籤、仿單或包裝，得免刊載前開注意事項。"}'::jsonb, '{"source_url":"https://data.gov.tw/dataset/173685","export_url":"https://data.fda.gov.tw/data/opendata/export/199/json","source_info_id":199}'::jsonb) on conflict (rule_id, version_label) do update set is_current = true, effective_to = null, rule_text = excluded.rule_text, raw_payload = excluded.raw_payload, source_snapshot = excluded.source_snapshot;
