insert into public.rule_versions (id, rule_id, source_id, version_label, source_record_id, source_hash, effective_from, is_current, rule_text, ingredient_names, cas_numbers, color_index_numbers, product_scope, limit_text, restriction_text, caution_text, conditions, raw_payload, source_snapshot) values ('1c66d385-b504-5ebd-98d5-6c70473e343f', '746c46bd-2adf-5e4c-8ae9-d6061848209c', '846c3ee9-b5b7-52ae-b7e1-400a6e4bdbbb', 'c8e43eba58158a68', '34', 'c8e43eba58158a68c4e647d9e64dd65e67d2cf8e9479f63334d6493fa0185096', '2026-06-25', true, 'Potassium or sodium hydroxide | (a1)2% (a2)4.5% (b)5% | (a)Sodium hydroxide、Potassium hydroxide 及Lithium hydroxide 之限量濃度是以Sodium hydroxide 之重量計。倘添加上開混合之成分，其總量不得超過其限量規定。 (a2)限美髮專業技術人士使用 (c)pH<11 | (a)含強鹼(alkali)、可能引起失明。 (b)含強鹼(alkali);使用時避免接觸眼睛，因可能引起失明，應放置於孩童伸手不及之場所儲存。', '["Potassium or sodium hydroxide","Potassium hydroxide","Sodium hydroxide"]'::jsonb, '["1310-58-3","1310-73-2"]'::jsonb, '[]'::jsonb, '(a)燙髮產品 (b)指甲角質劑 (c)其他用途，如pH調整液', '(a1)2% (a2)4.5% (b)5%', '(a)Sodium hydroxide、Potassium hydroxide 及Lithium hydroxide 之限量濃度是以Sodium hydroxide 之重量計。倘添加上開混合之成分，其總量不得超過其限量規定。 (a2)限美髮專業技術人士使用 (c)pH<11', '(a)含強鹼(alkali)、可能引起失明。 (b)含強鹼(alkali);使用時避免接觸眼睛，因可能引起失明，應放置於孩童伸手不及之場所儲存。', '{"limit_percent_values":[2,4.5,5],"max_limit_percent":5}'::jsonb, '{"編號":"34","成分名":"Potassium or sodium hydroxide","INCI名":"Potassium hydroxide/\r\nSodium hydroxide\t","CAS_NO.":"1310-58-3/\r\n1310-73-2","產品類型／使用範圍":"(a)燙髮產品\r\n(b)指甲角質劑\r\n(c)其他用途，如pH調整液\r\n","限量標準":"(a1)2%\r\n(a2)4.5%\r\n(b)5%\r\n","限制規定":"(a)Sodium hydroxide、Potassium hydroxide 及Lithium hydroxide 之限量濃度是以Sodium hydroxide 之重量計。倘添加上開混合之成分，其總量不得超過其限量規定。\r\n(a2)限美髮專業技術人士使用\r\n(c)pH<11","應刊載之注意事項":"(a)含強鹼(alkali)、可能引起失明。\r\n(b)含強鹼(alkali);使用時避免接觸眼睛，因可能引起失明，應放置於孩童伸手不及之場所儲存。"}'::jsonb, '{"source_url":"https://data.gov.tw/dataset/173685","export_url":"https://data.fda.gov.tw/data/opendata/export/199/json","source_info_id":199}'::jsonb) on conflict (rule_id, version_label) do update set is_current = true, effective_to = null, rule_text = excluded.rule_text, raw_payload = excluded.raw_payload, source_snapshot = excluded.source_snapshot;
