insert into public.rule_versions (id, rule_id, source_id, version_label, source_record_id, source_hash, effective_from, is_current, rule_text, ingredient_names, cas_numbers, color_index_numbers, product_scope, limit_text, restriction_text, caution_text, conditions, raw_payload, source_snapshot) values ('4d123a40-1efc-551e-8ac1-07f18460a2cd', 'c435c579-41a5-5fc2-930b-171157fedb15', '846c3ee9-b5b7-52ae-b7e1-400a6e4bdbbb', 'f9c721bb3bcef4d3', '40', 'f9c721bb3bcef4d33b854424c16040185a9d19d2c6dba017f04e49554e7213cd', '2026-06-25', true, 'Ammonium monofluorophosphate | 0.15%(以F計) | 倘混合使用其他我國準用之氟化合物，其氟總量不得超過0.15%。 | 1. 非藥用牙膏之氟含量達0.1至0.15%者，倘未刊載禁止孩童使用之標示，則應刊載：六歲以下孩童之使用量約為豌豆尺寸，且盡量避免吞食。若以其他途徑攝取氟化物者，應諮詢牙醫師或醫師。 2. 非藥用牙膏含氟化合物者，應刊載其氟含量。', '["Ammonium monofluorophosphate","Ammonium monofluorophosphate"]'::jsonb, '["20859-38-5","66115-19-3"]'::jsonb, '[]'::jsonb, '口腔製劑', '0.15%(以F計)', '倘混合使用其他我國準用之氟化合物，其氟總量不得超過0.15%。', '1. 非藥用牙膏之氟含量達0.1至0.15%者，倘未刊載禁止孩童使用之標示，則應刊載：六歲以下孩童之使用量約為豌豆尺寸，且盡量避免吞食。若以其他途徑攝取氟化物者，應諮詢牙醫師或醫師。 2. 非藥用牙膏含氟化合物者，應刊載其氟含量。', '{"limit_percent_values":[0.15],"max_limit_percent":0.15}'::jsonb, '{"編號":"40","成分名":"Ammonium monofluorophosphate\t","INCI名":"Ammonium monofluorophosphate\t","CAS_NO.":"20859-38-5/\r\n66115-19-3\t\r\n","產品類型／使用範圍":"口腔製劑","限量標準":"0.15%(以F計)","限制規定":"倘混合使用其他我國準用之氟化合物，其氟總量不得超過0.15%。","應刊載之注意事項":"1. 非藥用牙膏之氟含量達0.1至0.15%者，倘未刊載禁止孩童使用之標示，則應刊載：六歲以下孩童之使用量約為豌豆尺寸，且盡量避免吞食。若以其他途徑攝取氟化物者，應諮詢牙醫師或醫師。\r\n2. 非藥用牙膏含氟化合物者，應刊載其氟含量。"}'::jsonb, '{"source_url":"https://data.gov.tw/dataset/173685","export_url":"https://data.fda.gov.tw/data/opendata/export/199/json","source_info_id":199}'::jsonb) on conflict (rule_id, version_label) do update set is_current = true, effective_to = null, rule_text = excluded.rule_text, raw_payload = excluded.raw_payload, source_snapshot = excluded.source_snapshot;
