insert into public.rule_versions (id, rule_id, source_id, version_label, source_record_id, source_hash, effective_from, is_current, rule_text, ingredient_names, cas_numbers, color_index_numbers, product_scope, limit_text, restriction_text, caution_text, conditions, raw_payload, source_snapshot) values ('305fd6fb-cf06-5d10-af6e-ee19f446cc54', 'bcf61a32-c5e2-5a0f-8d23-5578d33afe5d', '846c3ee9-b5b7-52ae-b7e1-400a6e4bdbbb', '3a3ec32fa4d4ee03', '167', '3a3ec32fa4d4ee03f16de0637c2a52f7821e4347212f7e5967c21e35a1ed6ce4', '2026-06-25', true, 'Hydrogen peroxide, and other compounds or mixtures that release hydrogen peroxide | (a)12% (40 volumes)(含釋出之H2O2) (b)6% (含釋出之H2O2) | (b) 1.使用時牙齦或口腔若出現不適反應(如紅、腫、疼痛等)，請即停止使用，並諮詢牙醫師。 2.使用時如有牙齒敏感現象，請暫停使用，並諮詢牙醫師。 3.十二歲以下孩童、孕婦或授乳期婦女，不建議使用。 4.牙齦組織或口腔有病變，以及對本產品之成分有過敏者，請勿使用。 5.避免不當吞食。 6.使用時避免本產品接觸眼睛，若不慎觸及眼睛，請立即用清水沖洗。 7.使用牙齒美白劑期間不宜抽煙或嚼檳榔。 8.使用時儘量避免讓本產品直接接觸到牙齦。(居家使用之牙齒美白牙膏得免刊載此項) 9.使用超過十四天以上，應依照牙醫師指示使用。 10.本產品需置於孩童接觸不到之地方及避免陽光直射。', '["Hydrogen peroxide, and other compounds or mixtures that release hydrogen peroxide","Hydrogen peroxide"]'::jsonb, '["7722-84-1"]'::jsonb, '[]'::jsonb, '(a)染髮、燙髮產品 (b)居家使用之牙齒美白劑及牙膏', '(a)12% (40 volumes)(含釋出之H2O2) (b)6% (含釋出之H2O2)', '', '(b) 1.使用時牙齦或口腔若出現不適反應(如紅、腫、疼痛等)，請即停止使用，並諮詢牙醫師。 2.使用時如有牙齒敏感現象，請暫停使用，並諮詢牙醫師。 3.十二歲以下孩童、孕婦或授乳期婦女，不建議使用。 4.牙齦組織或口腔有病變，以及對本產品之成分有過敏者，請勿使用。 5.避免不當吞食。 6.使用時避免本產品接觸眼睛，若不慎觸及眼睛，請立即用清水沖洗。 7.使用牙齒美白劑期間不宜抽煙或嚼檳榔。 8.使用時儘量避免讓本產品直接接觸到牙齦。(居家使用之牙齒美白牙膏得免刊載此項) 9.使用超過十四天以上，應依照牙醫師指示使用。 10.本產品需置於孩童接觸不到之地方及避免陽光直射。', '{"limit_percent_values":[12,6],"max_limit_percent":12}'::jsonb, '{"編號":"167","成分名":"Hydrogen peroxide, and other compounds or mixtures that release hydrogen peroxide","INCI名":"Hydrogen peroxide","CAS_NO.":"7722-84-1","產品類型／使用範圍":"(a)染髮、燙髮產品\n(b)居家使用之牙齒美白劑及牙膏","限量標準":"(a)12% (40 volumes)(含釋出之H2O2)\n(b)6% (含釋出之H2O2)","限制規定":"","應刊載之注意事項":"(b)\n1.使用時牙齦或口腔若出現不適反應(如紅、腫、疼痛等)，請即停止使用，並諮詢牙醫師。\n2.使用時如有牙齒敏感現象，請暫停使用，並諮詢牙醫師。\n3.十二歲以下孩童、孕婦或授乳期婦女，不建議使用。\n4.牙齦組織或口腔有病變，以及對本產品之成分有過敏者，請勿使用。\n5.避免不當吞食。\n6.使用時避免本產品接觸眼睛，若不慎觸及眼睛，請立即用清水沖洗。\n7.使用牙齒美白劑期間不宜抽煙或嚼檳榔。\n8.使用時儘量避免讓本產品直接接觸到牙齦。(居家使用之牙齒美白牙膏得免刊載此項)\n9.使用超過十四天以上，應依照牙醫師指示使用。\n10.本產品需置於孩童接觸不到之地方及避免陽光直射。"}'::jsonb, '{"source_url":"https://data.gov.tw/dataset/173685","export_url":"https://data.fda.gov.tw/data/opendata/export/199/json","source_info_id":199}'::jsonb) on conflict (rule_id, version_label) do update set is_current = true, effective_to = null, rule_text = excluded.rule_text, raw_payload = excluded.raw_payload, source_snapshot = excluded.source_snapshot;
